import{_ as t,a as e,b as r,c as l}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o as i,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/magnet-transfer.md","filePath":"uk-UA/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"uk-UA/Other/magnet-transfer.md"};function h(p,a,m,c,g,u){return i(),d("div",null,[...a[0]||(a[0]=[o('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer завантажує файли з magnet link і автоматично передає їх у вибраний cloud storage channel.</p><p>Це зручно для перенесення anime-серій, відео, архівів та схожих файлів. Вставте magnet link, і ImgBed створить фонове завдання завантаження. Після завершення файл буде завантажено в ImgBed, а фінальне посилання з&#39;явиться у списку завантажень.</p><p><img src="'+t+'" alt="Magnet transfer" loading="lazy"></p><h2 id="де-це-використовувати" tabindex="-1">Де це використовувати <a class="header-anchor" href="#де-це-використовувати" aria-label="Permalink to &quot;Де це використовувати&quot;">​</a></h2><p>Вхід для magnet transfer знаходиться в зоні завантаження на головній сторінці.</p><p>Вставте magnet link у поле введення, виберіть <code>Transfer</code>, потім завантажте.</p><p><img src="'+e+'" alt="Завантаження anime" loading="lazy"></p><h2 id="перед-першим-використанням" tabindex="-1">Перед першим використанням <a class="header-anchor" href="#перед-першим-використанням" aria-label="Permalink to &quot;Перед першим використанням&quot;">​</a></h2><p>Спочатку налаштуйте magnet transfer в адмін-панелі.</p><p>Зазвичай потрібні:</p><ol><li>GitHub-акаунт для запуску download task.</li><li>Cloud upload channel, наприклад Google Drive або OneDrive.</li><li>Цільова upload directory.</li><li>Task timeout.</li></ol><p>Коли налаштування готові, поверніться на головну сторінку й вставте magnet link, щоб почати transfer.</p><h2 id="завантаження-magnet-link" tabindex="-1">Завантаження magnet link <a class="header-anchor" href="#завантаження-magnet-link" aria-label="Permalink to &quot;Завантаження magnet link&quot;">​</a></h2><ol><li>Вставте magnet link у поле завантаження на головній сторінці.</li><li>Переконайтеся, що режим встановлено як <code>Transfer</code>.</li><li>Натисніть upload.</li><li>Дочекайтеся, поки ImgBed створить magnet task.</li><li>Після запуску завдання використовуйте плаваючу панель <code>Magnet Tasks</code> у правому нижньому куті, щоб стежити за прогресом.</li></ol><p>Download і upload можуть зайняти час. Швидкість залежить від magnet-ресурсу, середовища GitHub runtime і вибраного cloud storage channel.</p><p><img src="'+r+'" alt="Magnet завантажується" loading="lazy"></p><h2 id="після-завершення" tabindex="-1">Після завершення <a class="header-anchor" href="#після-завершення" aria-label="Permalink to &quot;Після завершення&quot;">​</a></h2><p>Після завершення завдання у списку завантажень з&#39;являться назва файлу та посилання.</p><p>Для відео показується video preview, для зображень — image preview, а для інших файлів — звичайна іконка файлу.</p><p><img src="'+l+'" alt="Завантажене відео" loading="lazy"></p><p>Можна скопіювати:</p><table tabindex="0"><thead><tr><th>Тип посилання</th><th>Для чого</th></tr></thead><tbody><tr><td>Original link</td><td>Прямий доступ до файлу</td></tr><tr><td>Markdown</td><td>Markdown-дописи або нотатки</td></tr><tr><td>HTML</td><td>Код вебсторінки</td></tr><tr><td>BBCode</td><td>Форуми з підтримкою BBCode</td></tr></tbody></table><h2 id="панель-magnet-task" tabindex="-1">Панель Magnet Task <a class="header-anchor" href="#панель-magnet-task" aria-label="Permalink to &quot;Панель Magnet Task&quot;">​</a></h2><p>Панель magnet task у правому нижньому куті показує кількість завдань, назву, прогрес і фінальний статус.</p><p>Типові стани:</p><table tabindex="0"><thead><tr><th>Статус</th><th>Значення</th></tr></thead><tbody><tr><td>Waiting</td><td>Завдання створене й очікує запуску.</td></tr><tr><td>Downloading</td><td>Magnet-ресурс завантажується.</td></tr><tr><td>Uploading</td><td>Файл завантажено й він передається в cloud storage.</td></tr><tr><td>Completed</td><td>Upload успішний, посилання можна копіювати.</td></tr><tr><td>Failed</td><td>Завдання не завершилося успішно. Перевірте повідомлення й спробуйте ще раз.</td></tr></tbody></table><h2 id="поради" tabindex="-1">Поради <a class="header-anchor" href="#поради" aria-label="Permalink to &quot;Поради&quot;">​</a></h2><ul><li>Якщо magnet link містить кілька файлів, ImgBed намагається показати основний завершений файл.</li><li>Великі файли потребують більше часу. Дочекайтеся завершення завдання перед оновленням сторінки.</li><li>Якщо magnet-ресурс не має доступних peers, він може бути дуже повільним або не завантажитися.</li><li>Якщо у cloud account закінчилася квота, authorization прострочена або upload directory неправильна, завдання може впасти.</li><li>Video preview може з&#39;явитися через кілька секунд після завершення upload.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="після-вставлення-magnet-link-нічого-не-запускається" tabindex="-1">Після вставлення Magnet Link нічого не запускається <a class="header-anchor" href="#після-вставлення-magnet-link-нічого-не-запускається" aria-label="Permalink to &quot;Після вставлення Magnet Link нічого не запускається&quot;">​</a></h3><p>Переконайтеся, що magnet transfer увімкнений в адмін-панелі, а також вибрані придатний GitHub-акаунт і cloud channel.</p><h3 id="завантаження-завжди-повільне" tabindex="-1">Завантаження завжди повільне <a class="header-anchor" href="#завантаження-завжди-повільне" aria-label="Permalink to &quot;Завантаження завжди повільне&quot;">​</a></h3><p>Швидкість magnet залежить від самого ресурсу. Якщо немає доступних peers, завантаження може бути дуже повільним або неможливим.</p><h3 id="після-upload-немає-preview" tabindex="-1">Після upload немає preview <a class="header-anchor" href="#після-upload-немає-preview" aria-label="Permalink to &quot;Після upload немає preview&quot;">​</a></h3><p>Спершу перевірте, чи відкривається посилання на файл. Відеофайлам може знадобитися трохи часу для завантаження в браузері; також можна відкрити посилання напряму.</p><h3 id="що-перевірити-якщо-task-failed" tabindex="-1">Що перевірити, якщо task failed? <a class="header-anchor" href="#що-перевірити-якщо-task-failed" aria-label="Permalink to &quot;Що перевірити, якщо task failed?&quot;">​</a></h3><p>Перевірте, чи magnet link дійсний, чи працює cloud channel і чи правильна upload directory. Потім надішліть завдання ще раз.</p>',38)])])}const _=n(s,[["render",h]]);export{b as __pageData,_ as default};
